mapper.insert:
insert into store_address (storeAddrId, storeId, storeName, 
  phone, province, city, 
  zone, storeAddrDetail, longitude, 
  latitude, status, createdDate
  )
values (#{storeAddrId,jdbcType=BIGINT}, #{storeId,jdbcType=BIGINT}, #{storeName,jdbcType=VARCHAR}, 
  #{phone,jdbcType=VARCHAR}, #{province,jdbcType=VARCHAR}, #{city,jdbcType=VARCHAR}, 
  #{zone,jdbcType=VARCHAR}, #{storeAddrDetail,jdbcType=VARCHAR}, #{longitude,jdbcType=VARCHAR}, 
  #{latitude,jdbcType=VARCHAR}, #{status,jdbcType=TINYINT}, #{createdDate,jdbcType=TIMESTAMP}
  )

mapper.select:
select s.*, r.status as storeStatus, r.storeImgUrl, r.hours, round( 6378.138 * 2 * asin( sqrt(pow(sin((#{userLat} * pi() / 180 - s.latitude * pi() / 180 ) / 2),2) + cos(#{userLat} * pi() / 180) * cos(s.latitude * pi() / 180) * pow( sin((#{userLng} * pi() / 180 - s.longitude * pi() / 180) / 2),2))) *1000) AS distance from store_address s
inner join device d on d.storeAddressId=s.storeAddrId inner join user_info u on u.userId=d.proxyId
inner join store r on r.storeId=s.storeId s.status=1
AND s.storeId=#{storeId}
AND s.storeAddrId=#{storeAddrId}
AND u.userId = #{userId}
order by distance asc, r.storeId asc
order by r.storeId asc
limit ${offset}, ${limit}
